struct UltrafiltrationResistanceSeriesEngine: Sendable { func calculate(_ input: UltrafiltrationResistanceSeriesInput) throws -> UltrafiltrationResistanceSeriesResult { let v=[input.transmembranePressure,input.fluidViscosity,input.membraneResistance,input.foulingResistance,input.targetPermeateFlow]; guard v.allSatisfy(\.isFinite) else { throw UltrafiltrationResistanceSeriesError.nonFiniteInput }; guard input.transmembranePressure>0,input.fluidViscosity>0,input.targetPermeateFlow>0 else { throw UltrafiltrationResistanceSeriesError.nonPositivePressureViscosityOrFlow }; guard input.membraneResistance>0,input.foulingResistance>=0 else { throw UltrafiltrationResistanceSeriesError.invalidResistance }; let rt=input.membraneResistance+input.foulingResistance; let jc=input.transmembranePressure/(input.fluidViscosity*input.membraneResistance); let jf=input.transmembranePressure/(input.fluidViscosity*rt); let d=1-jf/jc; let a=input.targetPermeateFlow/jf; guard [rt,jc,jf,d,a].allSatisfy(\.isFinite),d>=0,d<1,a>0 else { throw UltrafiltrationResistanceSeriesError.numericalFailure }; return .init(totalResistance:rt,cleanMembraneFlux:jc,fouledMembraneFlux:jf,fluxDeclineFraction:d,requiredMembraneArea:a,modelName:"Resistance-in-series ultrafiltration model",limitationDescription:"Uses J = deltaP/[mu(Rm + Rf)] with constant resistances.") } }
